func modalMethod(m string) string {
	switch m {
	case "checkbox", "anchor":
		return m
	default:
		return "dialog"
	}
}

func modalClass(cfg ModalConfig) string {
	return joinClasses(
		"modal",
		modalPlacementClass(cfg.Placement),
		modalOpenClass(cfg.Open, cfg.Method),
		cfg.Class,
	)
}

// modalPlacementClass splits the placement string into individual segments
// and prefixes each with "modal-". E.g. "bottom sm:modal-middle" is returned
// as-is for the responsive prefix; bare tokens like "top" become "modal-top".
func modalPlacementClass(p string) string {
	p = strings.TrimSpace(p)
	if p == "" {
		return ""
	}
	var parts []string
	start := 0
	for i := 0; i <= len(p); i++ {
		if i == len(p) || p[i] == ' ' {
			seg := p[start:i]
			if seg == "" {
				start = i + 1
				continue
			}
			parts = append(parts, modalPlacementSegment(seg))
			start = i + 1
		}
	}
	return joinClasses(parts...)
}

// modalPlacementSegment prefixes a single placement token with "modal-"
// unless it already contains a colon (responsive variant like
// "sm:modal-middle"), in which case it is returned as-is.
func modalPlacementSegment(seg string) string {
	for i := 0; i < len(seg); i++ {
		if seg[i] == ':' {
			return seg
		}
	}
	return "modal-" + seg
}

func modalOpenClass(open bool, method string) string {
	if open && method != "dialog" {
		return "modal-open"
	}
	return ""
}

func modalBoxClass(cfg ModalConfig) string {
	return joinClasses("modal-box", glassClass(cfg.Glass), cfg.BoxClass)
}

func modalTriggerClass(cfg ModalConfig) string {
	if cfg.TriggerClass != "" {
		return cfg.TriggerClass
	}
	return "btn"
}

